
// Back button action
document.querySelector('.back-btn').addEventListener('click', () => {
    window.history.back();
});
document.querySelectorAll('.book-btn').forEach(button => {
  button.addEventListener('click', function() {
    const carCard = this.parentElement;
    const car = carCard.getAttribute('data-car');
    const price = carCard.getAttribute('data-price');
    // Redirect to booking page with car data as URL parameters
    window.location.href = `/bookings/booking.html?car=${car}&price=${price}`;
  });
});

// Back button function
